module dynamic_range_compressor(  
    input signed [4:0] audio_dec,  
    input signed [4:0] threshold,  
    output reg signed [4:0] audio_out  
);  
    always @(*) begin  
        if (audio_dec > threshold)  
            audio_out = threshold;  
        else  
            audio_out = audio_dec;  
    end  
endmodule
